@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800&display=swap');

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  font-family: 'DM Sans', sans-serif;
}

.auth-container {
  display: flex;
  width: 100%;
  min-height: 100vh;
  font-family: 'DM Sans', sans-serif;
}

.auth-left {
  width: 40%;
  min-height: 100vh;
  background: linear-gradient(160deg, #0a6b6b, #0e9090, #1aadad);
  background-image: 
    repeating-linear-gradient(
      45deg,
      rgba(255, 255, 255, 0.04) 1px,
      transparent 1px,
      transparent 28px
    ),
    linear-gradient(160deg, #0a6b6b, #0e9090, #1aadad);
  background-size: 28px 28px, 100% 100%;
  position: relative;
  padding: 3rem 2.5rem;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.auth-left-content {
  position: relative;
  z-index: 2;
}

.auth-headline {
  color: white;
  font-size: 2rem;
  font-weight: 800;
  line-height: 1.2;
  margin-bottom: 0.75rem;
}

.auth-subtext {
  color: white;
  font-size: 0.85rem;
  opacity: 0.65;
}

.mock-card {
  position: absolute;
  bottom: 25%;
  left: 50%;
  transform: translateX(-50%) rotate(-3deg);
  background: white;
  border-radius: 16px;
  padding: 1rem;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.25);
  width: 280px;
}

.mock-card-image {
  width: 100%;
  height: 160px;
  background: linear-gradient(135deg, #e5e7eb 25%, #f3f4f6 25%, #f3f4f6 50%, #e5e7eb 50%, #e5e7eb 75%, #f3f4f6 75%);
  background-size: 20px 20px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #9ca3af;
  font-size: 0.75rem;
}

.mock-card-blocks {
  display: flex;
  gap: 8px;
  margin-top: 10px;
}

.mock-block {
  height: 8px;
  background: #e5e7eb;
  border-radius: 4px;
}

.mock-block:nth-child(1) { width: 30%; }
.mock-block:nth-child(2) { width: 50%; }
.mock-block:nth-child(3) { width: 20%; }

.floating-badge {
  position: absolute;
  background: white;
  border-radius: 999px;
  padding: 0.3rem 0.8rem;
  font-size: 0.72rem;
  font-weight: 600;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
  color: #374151;
  z-index: 3;
}

.badge-slack {
  top: 20%;
  left: 15%;
}

.badge-google-ads {
  top: 30%;
  right: 10%;
}

.badge-zendesk {
  bottom: 40%;
  left: 5%;
}

.badge-shopify {
  bottom: 30%;
  right: 8%;
}

.auth-copyright {
  position: absolute;
  bottom: 1.5rem;
  left: 0;
  right: 0;
  text-align: center;
  color: white;
  font-size: 0.72rem;
  opacity: 0.4;
}

.auth-right {
  width: 60%;
  background: #f4f6f8;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
}

.auth-card {
  background: #ffffff;
  border: 1px solid #e5e7eb;
  border-radius: 20px;
  padding: 2.5rem 2.25rem;
  max-width: 400px;
  width: 100%;
  box-shadow: 0 4px 32px rgba(0, 0, 0, 0.07);
}

.auth-logo {
  width: 48px;
  height: 48px;
  margin: 0 auto 1rem;
  background: linear-gradient(135deg, #0e9090, #38b8d0);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.auth-logo span {
  color: white;
  font-weight: 700;
  font-size: 0.85rem;
}

.auth-card h2 {
  font-family: 'DM Sans', sans-serif;
  font-size: 1.4rem;
  font-weight: 700;
  text-align: center;
  color: #111;
  margin-bottom: 0.4rem;
}

.auth-card h2 .accent {
  color: #0e9090;
}

.auth-subtitle {
  font-size: 0.82rem;
  color: #9ca3af;
  text-align: center;
  margin-bottom: 1.6rem;
}

.form-group {
  margin-bottom: 1.25rem;
}

.form-group label {
  display: block;
  font-size: 0.8rem;
  font-weight: 600;
  color: #374151;
  margin-bottom: 0.4rem;
}

.form-group input {
  width: 100%;
  background: #ffffff;
  border: 1px solid #d1d5db;
  border-radius: 10px;
  padding: 0.72rem 1rem;
  font-size: 0.92rem;
  color: #111;
  font-family: 'DM Sans', sans-serif;
  transition: all 0.2s ease;
}

.form-group input::placeholder {
  color: #9ca3af;
}

.form-group input:focus {
  outline: none;
  border-color: #0e9090;
  box-shadow: 0 0 0 3px rgba(14, 144, 144, 0.12);
}

.auth-card form > button[type="submit"] {
  width: 100%;
  background: #111111;
  color: #ffffff;
  border: none;
  border-radius: 999px;
  padding: 0.82rem 1rem;
  font-size: 0.9rem;
  font-weight: 600;
  margin-top: 0.5rem;
  cursor: pointer;
  transition: background 0.2s;
  font-family: 'DM Sans', sans-serif;
}

.auth-card form > button[type="submit"]:hover:not(:disabled) {
  background: #333333;
}

.auth-card form > button[type="submit"]:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.social-row {
  display: flex;
  gap: 0.6rem;
  margin-top: 0.75rem;
}

.social-btn {
  flex: 1;
  background: white;
  border: 1px solid #e5e7eb;
  border-radius: 10px;
  padding: 0.6rem;
  font-size: 0.82rem;
  font-weight: 500;
  color: #374151;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  cursor: pointer;
  transition: all 0.2s ease;
  font-family: 'DM Sans', sans-serif;
}

.social-btn:hover {
  background: #f9fafb;
  border-color: #d1d5db;
}

.social-btn svg {
  width: 16px;
  height: 16px;
}

.switch-auth {
  font-size: 0.84rem;
  color: #6b7280;
  text-align: center;
  margin-top: 1.2rem;
}

.switch-auth button {
  background: none;
  border: none;
  color: #0e9090;
  font-weight: 700;
  cursor: pointer;
  text-decoration: none;
  padding: 0;
}

.switch-auth button:hover {
  text-decoration: underline;
}

.error-message {
  background: #fef2f2;
  border: 1px solid #fecaca;
  color: #b91c1c;
  border-radius: 10px;
  padding: 0.65rem 0.9rem;
  font-size: 0.82rem;
  margin-bottom: 1rem;
}

.success-message {
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  color: #15803d;
  border-radius: 10px;
  padding: 0.65rem 0.9rem;
  font-size: 0.82rem;
  margin-bottom: 1rem;
}

@media (max-width: 768px) {
  .auth-container {
    flex-direction: column;
  }

  .auth-left {
    display: none;
  }

  .auth-right {
    width: 100%;
    min-height: 100vh;
    background: #f4f6f8;
  }

  .auth-card {
    margin: 1.5rem;
    padding: 1.8rem 1.4rem;
  }
}

